def parse_nested_parens(paren_string: str) -> List[int]:
    """ Given a string comprising several parenthesis groups divided by spaces, this function calculates the maximum nesting depth for each group, e.g., (()()) shows two levels of nesting, and ((())) shows three.

    >>> parse_nested_parens('(()()) ((())) () ((())()())')
    [2, 3, 1, 3]
    """
    paren_groups = paren_string.split()
    max_depths = []

    for group in paren_groups:
        current_depth = 0
        max_depth = 0

        for char in group:
            if char == '(':
                current_depth += 1
                max_depth = max(max_depth, current_depth)
            elif char == ')':
                current_depth -= 1

        max_depths.append(max_depth)

    return max_depths",
